import pymongo
from pymongo import MongoClient
from bson.code import Code
import json
import re

class MongoDBAdvancedFilter:
    def __init__(self, connection_string="mongodb://localhost:27017/", database_name="advanced_filter_db"):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
        
    def create_sample_data(self, collection_name="products"):
        collection = self.db[collection_name]
        collection.delete_many({})
        
        sample_data = [
            {"name": "Laptop", "price": 1200, "stock": 15, "category": "Electronics", "specs": {"ram": 16, "storage": 512}},
            {"name": "Mouse", "price": 25, "stock": 100, "category": "Electronics", "specs": {"wireless": True}},
            {"name": "Keyboard", "price": 75, "stock": 50, "category": "Electronics", "specs": {"mechanical": True}},
            {"name": "Monitor", "price": 300, "stock": 30, "category": "Electronics", "specs": {"size": 27, "resolution": "4K"}},
            {"name": "Desk", "price": 450, "stock": 20, "category": "Furniture", "specs": {"material": "wood"}},
            {"name": "Chair", "price": 200, "stock": 35, "category": "Furniture", "specs": {"adjustable": True}},
            {"name": "Notebook", "price": 5, "stock": 200, "category": "Stationery", "specs": {"pages": 100}},
            {"name": "Pen", "price": 2, "stock": 500, "category": "Stationery", "specs": {"color": "blue"}},
            {"name": "Tablet", "price": 600, "stock": 25, "category": "Electronics", "specs": {"ram": 8, "storage": 256}},
            {"name": "Headphones", "price": 150, "stock": 40, "category": "Electronics", "specs": {"wireless": True, "noise_cancelling": True}}
        ]
        
        collection.insert_many(sample_data)
        print(f"Inserted {len(sample_data)} sample documents into '{collection_name}' collection")
        
    def execute_where_query(self, collection_name, js_expression):
        collection = self.db[collection_name]
        query = {"$where": js_expression}
        results = list(collection.find(query))
        return results
        
    def execute_mapreduce(self, collection_name, map_function, reduce_function, query=None):
        collection = self.db[collection_name]
        
        map_code = Code(map_function)
        reduce_code = Code(reduce_function)
        
        result = collection.map_reduce(
            map_code,
            reduce_code,
            "mapreduce_results",
            query=query
        )
        
        return list(result.find())
        
    def execute_aggregate_with_js(self, collection_name, pipeline):
        collection = self.db[collection_name]
        results = list(collection.aggregate(pipeline))
        return results
        
    def filter_with_function(self, collection_name, function_expression):
        collection = self.db[collection_name]
        func = Code(function_expression)
        query = {"$where": func}
        results = list(collection.find(query))
        return results
        
    def complex_where_filter(self, collection_name, conditions):
        js_conditions = []
        
        for condition in conditions:
            js_conditions.append(condition)
        
        js_expression = " && ".join([f"({c})" for c in js_conditions])
        return self.execute_where_query(collection_name, js_expression)
        
    def execute_custom_query(self, collection_name, user_expression):
        return self.execute_where_query(collection_name, user_expression)
        
    def find_with_regex_js(self, collection_name, field, pattern):
        js_expression = f"/{pattern}/.test(this.{field})"
        return self.execute_where_query(collection_name, js_expression)
        
    def mathematical_filter(self, collection_name, math_expression):
        js_expression = f"({math_expression})"
        return self.execute_where_query(collection_name, js_expression)
        
    def close(self):
        self.client.close()


def display_results(results, title="Results"):
    print(f"\n{'='*60}")
    print(f"{title}")
    print(f"{'='*60}")
    if results:
        for idx, doc in enumerate(results, 1):
            doc_copy = doc.copy()
            doc_copy.pop('_id', None)
            print(f"{idx}. {json.dumps(doc_copy, indent=2)}")
        print(f"\nTotal documents found: {len(results)}")
    else:
        print("No documents found")
    print(f"{'='*60}\n")


